flow.comment:
desc = Parse CSV into a list of raw contact rows, preserving row numbers for error reporting.
inputs = [{"name":"fileBytes","type":"byte[]","source":"context"}]
outputs = [
{"name":"rows","type":"RawContactRow[]","target":"context"},
{"name":"totalRows","type":"int","target":"context"}
]

desc = Initialize counters and an error collection for the import session.
inputs = [{"name":"totalRows","type":"int","source":"context"}]
outputs = [
{"name":"rowIndex","type":"int","target":"context"},
{"name":"importErrors","type":"ImportError[]","target":"context"}
]

desc = Read current row and normalize values (trim, casing, locale). 
inputs = [ 
{"name":"rows","type":"RawContactRow[]","source":"context"}, 
{"name":"rowIndex","type":"int","source":"context"} 
] 
outputs = [{"name":"currentRow","type":"RawContactRow","target":"context"}]

desc = Append row-level validation errors with a human-friendly message.
inputs = [
{"name":"rowIndex","type":"int","source":"context"},
{"name":"currentRow","type":"RawContactRow","source":"context"}
]
outputs = [{"name":"importErrors","type":"ImportError[]","target":"context"}]

desc = Skip duplicates within the current batch using email and phone as keys.
inputs = [
{"name":"currentRow","type":"RawContactRow","source":"context"},
{"name":"rows","type":"RawContactRow[]","source":"context"}
]
outputs = [{"name":"notDuplicate","type":"bool","target":"context"}]

desc = Record a batch-duplicate error for the row and continue the loop.
inputs = [
{"name":"rowIndex","type":"int","source":"context"},
{"name":"currentRow","type":"RawContactRow","source":"context"}
]
outputs = [{"name":"importErrors","type":"ImportError[]","target":"context"}]

desc = Convert row into domain Contact object using tenant defaults.
inputs = [
{"name":"tenantId","type":"UUID","source":"request"},
{"name":"currentRow","type":"RawContactRow","source":"context"}
]
outputs = [{"name":"contact","type":"Contact","target":"context"}]
